<?php namespace App\Repositories\Alumni;use App\Repositories\BaseRepository;use App\Models\Alumni\AlumniDonation;use Illuminate\Database\Eloquent\Collection;class AlumniDonationRepository extends BaseRepository{    public function __construct(AlumniDonation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByAlumni(int $alumniId): Collection    {        return $this->findByField('alumni_id', $alumniId);    }    public function findByPurpose(string $purpose): Collection    {        return $this->findByField('purpose', $purpose);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('donation_date', [$startDate, $endDate])->get();    }    public function getByAmountRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('amount', [$min, $max])->get();    }    public function getByPaymentMode(string $mode): Collection    {        return $this->findByField('payment_mode', $mode);    }    public function getTotalDonations(): float    {        return $this->query()->sum('amount');    }    public function getTotalDonationsByPurpose(): Collection    {        return $this->query()->selectRaw('purpose, SUM(amount) as total')->groupBy('purpose')->get();    }    public function getTotalDonationsByYear(int $year): float    {        return $this->query()->whereYear('donation_date', $year)->sum('amount');    }    public function getTopDonors(int $limit = 10): Collection    {        return $this->query()->selectRaw('alumni_id, SUM(amount) as total_donated')->groupBy('alumni_id')->orderBy('total_donated', 'desc')->limit($limit)->get();    }    public function recordDonation(array $data): AlumniDonation    {        return $this->create($data);    }}